type Sign = Neg | Zero | Pos
fn label(s: Sign) -> Ternary{1} = match s { Neg => <-->, Zero => <0>, Pos => <++> }
fn main() -> Ternary{1} = label(Zero)

nodule main
type Bytes = End | More(Binary{8}, Bytes)
fn main() -> Binary{8} = for b in More(0b1111_0000, More(0b0000_1111, End)), acc = 0b0000_0000 => xor(acc, b)

nodule bench
type Bytes = End | More(Binary{8}, Bytes)
fn checksum(bs: Bytes) -> Binary{8} = match bs { End => 0b0000_0000, More(b, rest) => xor(b, checksum(rest)) }
fn main() -> Binary{8} = checksum(More(0b1111_0000, More(0b0000_1111, End)))
